#include<bits/stdc++.h>
using namespace std;
int size(unsigned long long x){
	int i=0;
	while(x)x/=10,i++;
	return i;
}
string tenisk(int k,unsigned long long n){
	stack<int> st;
	string ans;
	while(n){
		st.push(n%k);
		n/=k;
	}
	while(st.size()){
		if(st.top()>=10){
			ans+=char('A'+st.top()-10);
		}
		else ans+=char('0'+st.top());
		st.pop();
	}
	return ans;
}
int main(void){
	string s,str;
	unsigned long long x;
	cin>>s;
	cout<<'{';
	for(int i=1;i<s.size()-1;i++){
		x=0;
		while(s[i]>='0'&&s[i]<='9')x=x*10+int(s[i]-'0'),i++;
		str=tenisk(16,x);
		if(size(x)>=str.size()+2)cout<<"0x"<<str;
		else cout<<x;
		if(!(i==s.size()-1))cout<<','; 
	}cout<<'}';
	return false;
}
